import React from "react";
import { useAuth } from "../LoginPage/AuthContext"; // AuthContext yolunu kontrol et
import { useNavigate } from "react-router-dom";

const MainPage: React.FC = () => {
    const { isAuthenticated } = useAuth();
    const navigate = useNavigate();

    if (!isAuthenticated) {
        navigate("/login");
        return null; // Eğer giriş yapılmamışsa, yönlendirme sonrası boş render et
    }

    return (
        <div>
            <h1>Dashboard</h1>
            <p>Giriş başarılı! Hoş geldiniz.</p>
        </div>
    );
};

export default MainPage;
